mapper.select:
select count(*) from
market_tbl where market_status = #{status}

	and market_title like '%'||#{searchKeyword}||'%'


	and market_writer = #{searchKeyword}

select mt.market_no, mt.market_title, to_char(mt.market_date, 'yyyy-mm-dd HH24:mi:ss') as market_date, mt.market_writer, mt.view_count, mt.sell_addr, mt.sell_price, ( select count(*) from market_like_tbl ml where ml.market_no = mt.market_no ) as like_count,
( select count(*) from market_report_tbl mr where mr.market_no = mt.market_no ) as report_count, ( select market_file_path from ( select mf.market_file_path from market_file_tbl mf where mf.market_no = mt.market_no order by mf.market_file_no asc ) where rownum = 1 ) as marketThumb from market_tbl mt join member_tbl m on (mt.market_writer = m.member_id) where market_status = #{status}
and market_title like '%'||#{searchKeyword}||'%'
and market_writer = #{searchKeyword}
order by market_no desc order by market_no asc order by view_count desc order by like_count desc order by sell_price desc
offset #{page}*#{size} rows fetch next #{size} rows only

select count(*) from market_like_tbl
where market_no = #{marketNo}
and member_id = #{memberId}

mapper.delete:
delete from market_like_tbl
	where market_no = #{marketNo}
	and member_id = #{memberId}

mapper.select:
select t.market_comment_no, t.market_no, t.market_comment_writer, t.market_comment_content, to_char(t.market_comment_date, 'yyyy-mm-dd hh24:mi:ss') market_comment_date, t.market_recomment_no, t.is_secret, t.is_edited, m.member_thumb from ( select * from market_comment_tbl where market_no = #{marketNo}
/* 1. 부모 댓글 10개를 뽑을 때 필터와 정렬을 싹 다 적용! */ start with market_comment_no in ( select market_comment_no from ( select market_comment_no from market_comment_tbl where market_no = #{marketNo} and market_recomment_no is null
and is_secret = 1
and is_secret = 0
order by market_comment_no asc
order by market_comment_no desc
) offset #{page} * #{size} rows fetch next #{size} rows only )
/* 2. 자식 답글들 전부 끌고 오기 */ connect by prior market_comment_no = market_recomment_no
/* 3. 전체 데이터를 조건에 맞춰 정렬해서 프론트로 넘김 */
order by market_comment_no asc
order by market_comment_no desc
) t left join member_tbl m on (t.market_comment_writer = m.member_id)
